function TokenInfo() {
  const { tokenData, timeUntilExpiry } = useAuth();
  const [remaining, setRemaining] = useState(timeUntilExpiry);

  useEffect(() => {
    const interval = setInterval(() => {
      if (tokenData) {
        setRemaining(getTimeUntilExpiry(tokenData));
      }
    }, 1000);
    return () => clearInterval(interval);
  }, [tokenData]);

  if (!tokenData) return null;

  const formatTime = (ms) => {
    if (ms === null) return 'Unknown';
    const seconds = Math.floor(ms / 1000);
    const minutes = Math.floor(seconds / 60);
    const hours = Math.floor(minutes / 60);
    if (hours > 0) return `${hours}h ${minutes % 60}m ${seconds % 60}s`;
    if (minutes > 0) return `${minutes}m ${seconds % 60}s`;
    return `${seconds}s`;
  };

  const maskedToken = tokenData.access_token
    ? `${tokenData.access_token.substring(0, 10)}...${tokenData.access_token.substring(tokenData.access_token.length - 6)}`
    : 'N/A';

  return (
    <div style={styles.tokenInfo}>
      <h3 style={styles.sectionTitle}>Token Information</h3>
      <div style={styles.tokenGrid}>
        <div style={styles.tokenLabel}>Access Token:</div>
        <div style={styles.tokenValue}>
          <code style={styles.codeSnippet}>{maskedToken}</code>
        </div>
        <div style={styles.tokenLabel}>Token Type:</div>
        <div style={styles.tokenValue}>{tokenData.token_type || 'Bearer'}</div>
        <div style={styles.tokenLabel}>Scope:</div>
        <div style={styles.tokenValue}>{tokenData.scope || 'N/A'}</div>
        <div style={styles.tokenLabel}>Expires In:</div>
        <div style={styles.tokenValue}>
          <span
            style={{
              ...styles.expiryBadge,
              backgroundColor: remaining && remaining < 120000 ? '#fee2e2' : '#dcfce7',
              color: remaining && remaining < 120000 ? '#dc2626' : '#16a34a',
            }}
          >
            {formatTime(remaining)}
          </span>
        </div>
      </div>
    </div>
  );
}

function UserProfile() {
  const { user } = useAuth();

  if (!user) return null;
  if (user.fallback) {
    return (
      <div style={styles.profileCard}>
        <p style={styles.fallbackText}>User info unavailable, but you are authenticated.</p>
      </div>
    );
  }

  return (
    <div style={styles.profileCard}>
      <h3 style={styles.sectionTitle}>User Profile</h3>
      <div style={styles.profileContent}>
        {user.picture && (
          <img src={user.picture} alt="Profile" style={styles.avatar} referrerPolicy="no-referrer" />
        )}
        <div style={styles.profileDetails}>
          <div style={styles.profileName}>{user.name || 'Unknown User'}</div>
          <div style={styles.profileEmail}>{user.email || ''}</div>
          {user.email_verified !== undefined && (
            <span
              style={{
                ...styles.verifiedBadge,
                backgroundColor: user.email_verified ? '#dcfce7' : '#fee2e2',
                color: user.email_verified ? '#16a34a' : '#dc2626',
              }}
            >
              {user.email_verified ? '✓ Verified' : '✗ Unverified'}
            </span>
          )}
        </div>
      </div>
    </div>
  );
}

function ApiDemo() {
  const { authFetch } = useAuth();
  const [result, setResult] = useState(null);
  const [apiLoading, setApiLoading] = useState(false);
  const [apiError, setApiError] = useState(null);

  const callApi = async () => {
    setApiLoading(true);
    setApiError(null);
    try {
      const response = await authFetch('https://www.googleapis.com/oauth2/v3/userinfo');
      const data = await response.json();
      setResult(JSON.stringify(data, null, 2));
    } catch (err) {
      setApiError(err.message);
    } finally {
      setApiLoading(false);
    }
  };

  return (
    <div style={styles.apiDemo}>
      <h3 style={styles.sectionTitle}>API Call Demo</h3>
      <p style={styles.apiDescription}>
        Test authenticated API calls using the <code>authFetch</code> helper.
      </p>
      <button onClick={callApi} disabled={apiLoading} style={styles.apiButton}>
        {apiLoading ? 'Loading...' : 'Call Userinfo API'}
      </button>
      {apiError && <div style={styles.apiError}>Error: {apiError}</div>}
      {result && (
        <pre style={styles.apiResult}>{result}</pre>
      )}
    </div>
  );
}

function Dashboard() {
  const { user, logout, error } = useAuth();

  return (
    <div style={styles.dashboard}>
      <header style={styles.header}>
        <div style={styles.headerContent}>
          <h1 style={styles.headerTitle}>OAuth 2.0 SPA</h1>
          <div style={styles.headerRight}>
            {user && !user.fallback && (
              <span style={styles.headerUser}>
                {user.picture && (
                  <img
                    src={user.picture}
                    alt=""
                    style={styles.headerAvatar}
                    referrerPolicy="no-referrer"
                  />
                )}
                {user.name || user.email}
              </span>
            )}
            <button onClick={logout} style={styles.logoutButton}>
              Sign Out
            </button>
          </div>
        </div>
      </header>

      <main style={styles.main}>
        <ErrorBanner error={error} />

        <div style={styles.grid}>
          <UserProfile />
          <TokenInfo />
          <ApiDemo />
        </div>
      </main>
    </div>
  );
}

function App() {
  const { isAuthenticated, loading } = useAuth();

  if (loading) {
    return <LoadingSpinner />;
  }

  return isAuthenticated ? <Dashboard /> : <LoginPage />;
}

